INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation, order_index) VALUES
('af9f5e2c-4519-4a91-b981-e3e852187324', 'Trong cụm ''an apple'', nối âm xảy ra thế nào?', 'multiple_choice', '["Nuốt âm /n/","Âm /n/ nối với /æ/ thành /ə næpl/","Nối /p/ với /l/","Không nối"]'::jsonb, 'Âm /n/ nối với /æ/ thành /ə næpl/', 'Phụ âm /n/ luyến sang nguyên âm /æ/.', 2),
('af9f5e2c-4519-4a91-b981-e3e852187324', 'Đọc liền mạch ''stand up'', âm phát ra nghe giống thế nào?', 'multiple_choice', '["stan - dup","stand - up","sta - nup","stan - p"]'::jsonb, 'stan - dup', 'Âm /d/ luyến sang /ʌ/ tạo thành ''dup''.', 3),
('75f049b1-4379-4a1f-b357-0a6db7bf7edb', 'Nuốt âm (Elision) là hiện tượng gì?', 'multiple_choice', '["Lược bỏ một hoặc nhiều âm để nói nhanh","Thêm một âm","Nhấn mạnh tất cả âm","Đọc to lên"]'::jsonb, 'Lược bỏ một hoặc nhiều âm để nói nhanh', 'Elision là làm rơi rụng âm yếu để phát âm trơn tru.', 1),
('75f049b1-4379-4a1f-b357-0a6db7bf7edb', 'Trong cụm ''next day'', phụ âm nào thường bị nuốt?', 'multiple_choice', '["Âm /n/","Âm /x/","Âm /t/ trong ''next''","Âm /d/"]'::jsonb, 'Âm /t/ trong ''next''', 'Cụm phụ âm /k-s-t-d/, âm /t/ ở giữa bị nuốt đi.', 2),
('75f049b1-4379-4a1f-b357-0a6db7bf7edb', 'Từ ''comfortable'' thực tế thường chỉ còn mấy âm tiết khi nói nhanh?', 'multiple_choice', '["4 âm tiết","5 âm tiết","3 âm tiết","2 âm tiết"]'::jsonb, '3 âm tiết', 'Nuốt âm yếu schwa tạo thành 3 âm tiết /ˈkʌmftəbl/.', 3),
('6afaf984-4857-4850-884a-a6693be7764c', '''Wanna'' là dạng rút gọn của cụm nào?', 'multiple_choice', '["want a","want to","went to","will not"]'::jsonb, 'want to', '''Want to'' rút gọn thành ''wanna''.', 1),
('6afaf984-4857-4850-884a-a6693be7764c', '''I gotta go'', từ ''gotta'' là viết tắt của cụm nào?', 'multiple_choice', '["got to","go to","get a","going to"]'::jsonb, 'got to', 'Cấu trúc ''have got to / got to'' rút gọn thành ''gotta''.', 2),
('6afaf984-4857-4850-884a-a6693be7764c', 'Cụm ''let me'' thường được rút gọn thành gì trong văn nói?', 'multiple_choice', '["let''s","lemme","leave","lenne"]'::jsonb, 'lemme', '''Let me'' rút gọn thành ''lemme''.', 3),
('a08fb0a9-f200-41ed-90b9-3167dbe13866', 'Điền từ: ''I ___ play the piano when I was 5 years old.''', 'multiple_choice', '["can","could","may","should"]'::jsonb, 'could', 'Khả năng trong quá khứ dùng ''could''.', 1),
('8de64bb9-c2d0-43e8-abf6-d574dd98d740', 'Điền từ để xin phép lịch sự: ''___ I use your pen?''', 'multiple_choice', '["Must","Might","May","Will"]'::jsonb, 'May', '''May I'' dùng để xin phép một cách trang trọng.', 1),
('5e9e0def-ef8e-46f0-b9bd-d5e76ffa9c19', 'Chuyển sang bị động: ''This work must be ___ by tomorrow.''', 'multiple_choice', '["do","did","done","doing"]'::jsonb, 'done', 'Cấu trúc bị động của modal verb là Modal + be + V3/ed.', 1),
('7c74ea6e-408f-4b32-8c3f-758849c94a06', 'Chỉ sự bắt buộc do nội quy, bạn dùng từ nào: ''You ___ wear a uniform at school.''', 'multiple_choice', '["can","might","must","may"]'::jsonb, 'must', '''Must'' diễn tả sự bắt buộc, quy định.', 1),
('bdd1cff0-656d-4b5a-b07b-922d6484af9c', 'Đưa ra lời đề nghị giúp đỡ: ''___ I carry this bag for you?''', 'multiple_choice', '["Shall","Need","Must","Would"]'::jsonb, 'Shall', '''Shall I...'' dùng để ngỏ ý giúp đỡ.', 1),
('0c4a7555-1ba4-4dc5-b58b-763633cd5a93', 'Đưa ra lời khuyên: ''You look tired. You ___ go to bed early.''', 'multiple_choice', '["should","can","may","will"]'::jsonb, 'should', '''Should'' dùng để đưa ra lời khuyên.', 1),
('205501be-2ee1-47bc-b8c8-def285289e37', 'Dự đoán có căn cứ chắc chắn: ''Look at those dark clouds! It ___ rain.''', 'multiple_choice', '["must","is going to","can","should"]'::jsonb, 'is going to', '''Be going to'' diễn tả dự đoán có dấu hiệu ở hiện tại.', 1),
('882be395-b3a6-4fd9-8928-9d8441c6af70', 'Nhờ vả lịch sự: ''___ you please open the window?''', 'multiple_choice', '["Would","Should","May","Must"]'::jsonb, 'Would', '''Would you please'' là cách nhờ vả rất lịch sự.', 1),
('7eaf2c1f-72d3-46c2-b2b6-1172f78cd7fb', 'Giới từ chỉ nơi chốn: ''She is waiting ___ the bus stop.''', 'multiple_choice', '["in","on","at","to"]'::jsonb, 'at', '''At'' dùng cho một địa điểm cụ thể (bus stop).', 1),
('a6f97bb0-14ca-4698-a965-fda4ae1599b6', 'Giới từ chỉ sự di chuyển: ''We walked ___ the park to get home.''', 'multiple_choice', '["through","on","at","in"]'::jsonb, 'through', '''Through'' nghĩa là đi xuyên qua.', 1),
('ea2150a5-b8c9-4fe2-8946-ba0befe866d0', 'Giới từ chỉ thời gian: ''My birthday is ___ October 15th.''', 'multiple_choice', '["in","on","at","for"]'::jsonb, 'on', 'Dùng ''on'' trước ngày tháng cụ thể.', 1),
('e687077e-7682-4866-8adc-aeb6e4dc3bf9', 'Giới từ đi với tính từ: ''I am very interested ___ learning English.''', 'multiple_choice', '["in","on","at","about"]'::jsonb, 'in', 'Cấu trúc cố định ''interested in'' (quan tâm đến).', 1);